import React, { useState, useEffect } from 'react';
import { ThemeContext } from './ThemeContext';
import Header from './Header';
import UserList from './UserList';
import Counter from './Counter';
import ThemeToggle from './ThemeToggle';
import Footer from './Footer';
import './App.css';

function App() {
  const [theme, setTheme] = useState('Светлая');
  const [showCounter, setShowCounter] = useState(true);
  const [users, setUsers] = useState([]);

  // Цикл
  useEffect(() => {
    setUsers([
      { id: 1, name: 'Матвей' },
      { id: 2, name: 'Иван' },
      { id: 3, name: 'Антон' },
      { id: 4, name: 'Наталья' },
      { id: 5, name: 'Сергей' },
      { id: 6, name: 'Алексей' },
      { id: 7, name: 'Андрей' },
      { id: 8, name: 'Арсений' },
    ]);
  }, []);

  const toggleTheme = () => {
    setTheme((prev) => (prev === 'Светлая' ? 'Тёмная' : 'Светлая'));
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      <div className={`App ${theme}`}>
        <Header title=" работа №1 REACT" />

        {/* Условное отображение компонента */}
        {showCounter ? <Counter /> : <p>Счётчик скрыт</p>}
        <button onClick={() => setShowCounter(!showCounter)}>
          {showCounter ? 'Скрыть' : 'Показать'} счётчик
        </button>

        {/* Отображение компонента в цикле */}
        <UserList users={users} />

        {/* Компонент с useContext */}
        <ThemeToggle />

        <Footer year={2026} />
      </div>
    </ThemeContext.Provider>
  );
}

export default App;
